            long newTime = time + 1;
            if (dist[node] != -1 && newTime < dist[node]) {
                dist[node] = newTime;
                pq.offer(new long[]{newTime, node});
            }
        }

        return dist[(int)(n - 1)] == -1 ? -1 : dist[(int)(n - 1)];
    }
}
