import { priorityQueue } from 'typescript-collections';

function solve(n, edges) {
    const adj = new Map();
    for (const [u, v, s, e] of edges) {
        if (!adj.has(u)) {
            adj.set(u, []);
        }
        adj.get(u).push({ v, s, e });
    }

    const dist = new Array(n).fill(-1);
    dist[0] = 0;

    const pq = new priorityQueue((a, b) => a[0] - b[0]);
    pq.enqueue([0, 0]); // [time, node]

    while (!pq.isEmpty()) {
        const [time, node] = pq.dequeue();
        if (node === n - 1) break;

        if (dist[node] < time) continue;

        if (adj.has(node)) {
            for (const [v, s, e] of adj.get(node)) {
                if (time >= s && time <= e) {
                    const newTime = time + 1;
                    if (dist[v] === -1 || newTime < dist[v]) {
                        dist[v] = newTime;
                        pq.enqueue([newTime, v]);
                    }
                }
            }
        }

        // Option to wait at current node
        if (dist[node] !== -1) {
            const newTime = time + 1;
            if (dist[node] < newTime && dist[v] === -1) {
                dist[node] = newTime;
                pq.enqueue([newTime, node]);
            }
        }
    }

    return dist[n - 1] === -1 ? -1 : dist[n - 1];
}

