import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges) {
        Map<Long, List<int[]>> adj = new HashMap<>();
        for (long[] edge : edges) {
            long u = edge[0];
            long v = edge[1];
            long s = edge[2];
            long e = edge[3];
            if (!adj.containsKey(u)) {
                adj.put(u, new ArrayList<>());
            }
            adj.get(u).add(new int[]{v, (int)s, (int)e});
        }

        long[] dist = new long[(int)n];
        Arrays.fill(dist, -1);
        dist[0] = 0;

        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        pq.offer(new long[]{0, 0});

        while (!pq.isEmpty()) {
            long[] curr = pq.poll();
            long time = curr[0];
            long node = curr[1];
            if (node == n - 1) break;

            if (dist[node] < time) continue;

            if (adj.containsKey(node)) {
                for (int[] edge : adj.get(node)) {
                    long v = edge[0];
                    int s = edge[1];
                    int e = edge[2];
                    if (time >= s && time <= e) {
                        long newTime = time + 1;
                        if (dist[v] == -1 || newTime < dist[v]) {
                            dist[v] = newTime;
                            pq.offer(new long[]{newTime, v});
                        }
                    }
                }
            }

            long newTime = time + 1;
            if (dist[node] < newTime && dist[node] != -1) {
                dist[node] = newTime;
                pq.offer(new long[]{newTime, node});
            }
        }

        return dist[(int)(n - 1)] == -1 ? -1 : dist[(int)(n - 1)];
    }
}
